/**
 * @summary Get messages in a conversation (paginated)
 */
export const getListMessagesUrl = (id: number, params?: ListMessagesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/conversations/${id}/messages?${stringifiedParams}`
    : `/api/conversations/${id}/messages`;
};

export const listMessages = async (
  id: number,
  params?: ListMessagesParams,
  options?: RequestInit,
): Promise<MessagesPage> => {
  return customFetch<MessagesPage>(getListMessagesUrl(id, params), {
    ...options,
    method: "GET",
  });
};

export const getListMessagesQueryKey = (
  id: number,
  params?: ListMessagesParams,
) => {
  return [
    `/api/conversations/${id}/messages`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListMessagesQueryOptions = <
  TData = Awaited<ReturnType<typeof listMessages>>,
  TError = ErrorType<ErrorResponse>,
>(
  id: number,
  params?: ListMessagesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listMessages>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListMessagesQueryKey(id, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listMessages>>> = ({
    signal,
  }) => listMessages(id, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listMessages>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

